        {/* </View>
      </Swiper> */}

      {/* </Swiper> */}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    marginVertical: 10,
    height: 200,
    alignItems: 'center',
  },
  bannerContainer: {
    flex: 1,
  },
  bannerSlide: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  bannerImage: {
    width: '100%',
    height: '100%',
    resizeMode: 'cover',
  },
});

export default Banner;
